const endpoints = [
  { name: 'MAS Orchestrator', url: 'http://192.168.0.188:8001/health', vm: '188', critical: true },
  { name: 'MAS n8n', url: 'http://192.168.0.188:5678/healthz', vm: '188', critical: true },
  { name: 'MINDEX API', url: 'http://192.168.0.189:8000/health', vm: '189', critical: true },
  { name: 'Qdrant', url: 'http://192.168.0.189:6333/healthz', vm: '189', critical: true },
  { name: 'Website', url: 'http://192.168.0.187:3000', vm: '187', critical: true },
  { name: 'MycoBrain', url: 'http://192.168.0.187:8003/health', vm: '187', critical: false },
  { name: 'Ollama', url: 'http://192.168.0.188:11434/api/tags', vm: '188', critical: false },
  { name: 'MYCA n8n', url: 'http://192.168.0.191:5679/healthz', vm: '191', critical: false }
];

return endpoints.map(e => ({ json: e }));

const items = $input.all();
const now = new Date().toISOString();
const results = [];
const failures = [];

for (const item of items) {
  const endpoint = item.json;
  const statusCode = endpoint.statusCode || endpoint.status_code || 0;
  const isUp = statusCode >= 200 && statusCode < 500;
  const responseTime = endpoint.responseTime || endpoint.response_time_ms || 0;

  const result = {
    name: endpoint.name || 'unknown',
    url: endpoint.url || '',
    vm: endpoint.vm || '',
    status: isUp ? 'up' : 'down',
    status_code: statusCode,
    response_time_ms: responseTime,
    critical: endpoint.critical || false,
    timestamp: now
  };

  results.push(result);

  if (!isUp) {
    failures.push(result);
  }
}

const summary = {
  total: results.length,
  up: results.filter(r => r.status === 'up').length,
  down: results.filter(r => r.status === 'down').length,
  critical_down: failures.filter(f => f.critical).length,
  avg_response_ms: Math.round(results.reduce((s, r) => s + r.response_time_ms, 0) / results.length),
  results: results,
  failures: failures,
  timestamp: now
};

return [{ json: summary }];
